import {
  // POST_NEW_LOCATION_SUCCESS,
  POST_NEW_LOCATION_ERROR,
  FETCH_LOCATION_SUCCESS,
  FETCH_LOCATION_ERROR,
  RESET,
} from '../actions/actionNames';

const initialState = {
  location: {},
  error: {},
};

const postNewLocationError = (state, error) => ({ ...state, error });
const fetchLocationSuccess = (state, location) => ({ ...state, location });
const fetchLocationError = (state, error) => ({ ...state, error });

const addLocationReducer = (state = initialState, action) => {
  switch (action.type) {
    case POST_NEW_LOCATION_ERROR:
      return postNewLocationError(state, action.error);
    case FETCH_LOCATION_SUCCESS:
      return fetchLocationSuccess(state, action.payload);
    case FETCH_LOCATION_ERROR:
      return fetchLocationError(state, action.error);
    case RESET:
      return initialState;
    default:
      return state;
  }
};

export default addLocationReducer;
