import {
  // POST_NEW_PRODUCT_SUCCESS,
  POST_NEW_PRODUCT_ERROR,
  FETCH_PRODUCT_SUCCESS,
  FETCH_PRODUCT_ERROR,
  RESET,
} from '../actions/actionNames';

const initialState = {
  product: {},
  error: {},
};

const postNewProductError = (state, error) => ({ ...state, error });
const fetchProductSuccess = (state, product) => ({ ...state, product });
const fetchProductError = (state, error) => ({ ...state, error });

const addProductReducer = (state = initialState, action) => {
  switch (action.type) {
    case POST_NEW_PRODUCT_ERROR:
      return postNewProductError(state, action.error);
    case FETCH_PRODUCT_SUCCESS:
      return fetchProductSuccess(state, action.payload);
    case FETCH_PRODUCT_ERROR:
      return fetchProductError(state, action.error);
    case RESET:
      return initialState;
    default:
      return state;
  }
};

export default addProductReducer;
