import { required, isFloatNumber } from '../../utils/validations';

export const PRODUCT_STATUSES = {
  ACTIV: 'Activ',
  CASABIL: 'Casabil',
  CASAT: 'Casat',
};

export const amortizationPeriod = (value) => {
  if (!new RegExp('^[1-9][0-9]?,([0-9]|1[0-1])$').test(value)) {
    return ['Text Invalid', 'Format valid: AA,LL'];
  }
  return [];
};

