import { Button } from '@material-ui/core';

export const gridColumnLabels = {
  _id: ' ',
  lastName: 'Nume',
  firstName: 'Prenume',
};

export const computeGridColumns = (props) =>
  Object.keys(gridColumnLabels).map((key) => {
    const defaultWidth = 180;
    const defaultObject = {
      field: key,
      headerName: gridColumnLabels[key],
      width: defaultWidth,
    };

    switch (key) {
      case '_id':
        return {
          ...defaultObject,
          width: 120,
          renderCell: (params) => {
            return (
              <Button
                variant="contained"
                color="primary"
                size="small"
                style={{ marginLeft: 16 }}
                onClick={() =>
                  props.history.push(`/professors/${params.value}`)
                }
              >
                Detalii
              </Button>
            );
          },
        };

      default:
        return defaultObject;
    }
  });
