import {
  FETCH_LOCATIONS_SUCCESS,
  FETCH_LOCATIONS_ERROR,
  RESET,
} from '../actions/actionNames';

const initialState = {
  locations: [],
  error: {},
};

const fetchLocationsSuccess = (state, locations) => ({ ...state, locations });
const fetchLocationsError = (state, error) => ({ ...state, error });

const locationsReducer = (state = initialState, action) => {
  switch (action.type) {
    case FETCH_LOCATIONS_SUCCESS:
      return fetchLocationsSuccess(state, action.payload);
    case FETCH_LOCATIONS_ERROR:
      return fetchLocationsError(state, action.error);
    case RESET:
      return initialState;
    default:
      return state;
  }
};

export default locationsReducer;
