import React, { useState, useEffect } from 'react';
import { useDispatch, useSelector } from 'react-redux';
import { Container, makeStyles, Button, Box, Grid } from '@material-ui/core';
import { fetchProducts } from '../products/actions';
import { QrCodeScanner } from '../../components';

const useStyles = makeStyles({
  navbarDisplayFlex: {
    height: '80vh',
  },
  searchHeader: {
    display: 'flex',
    alignItems: 'center',
    justifyContent: 'space-between',
  },
  searchRightBox: {
    display: 'flex',
  },
  title: {
    fontSize: '25px',
  },
  qrWrapper: {
    width: '50%',
  },
  scanResult: {
    fontSize: '20px',
  },
  foundResult: {
    fontSize: '30px',
    color: '#1D6F42',
    textAlign: 'center',
  },
});

const ScanProducts = (props) => {
  const dispatch = useDispatch();
  const classes = useStyles();
  const { products } = useSelector((state) => state.products);

  const [scanResult, setScanResult] = useState('');
  const [disableSearch, setDisableSearch] = useState(true);
  const [productId, setProductId] = useState('');

  useEffect(() => {
    dispatch(fetchProducts());
  }, [dispatch]);

  useEffect(() => {
    products.forEach((product) => {
      if (product.inventoryNumber === scanResult) {
        setProductId(product._id);
        setDisableSearch(false);
        return true;
      }
    });
  }, [scanResult, products]);

  const onQrCodeSuccess = (result) => {
    if (result !== scanResult) {
      setScanResult(result);
    }
  };

  return (
    <Container className={classes.navbarDisplayFlex}>
      <Box my={3} className={classes.searchHeader}>
        <Box>
          <p className={classes.title}>Scaneaza Produs</p>
        </Box>
      </Box>
      <Grid container direction="column" alignItems="center">
        <div className={classes.qrWrapper}>
          <QrCodeScanner
            config={{
              fps: 10,
              qrBox: 250,
              disableFlip: false,
            }}
            onQrCodeSuccess={onQrCodeSuccess}
            onQrCodeError={() => {}}
          />
          <Box my={2}>
            {!disableSearch ? (
              <p className={classes.foundResult}> PRODUS GASIT </p>
            ) : (
              ''
            )}
          </Box>

          <Grid container justify="space-between" alignItems="center">
            <Box my={2}>
              <p className={classes.scanResult}> SCAN RESULT: {scanResult}</p>
            </Box>
            <Box my={2}>
              <Button
                variant="contained"
                color="primary"
                size="medium"
                type="button"
                onClick={() => props.history.push(`/products/${productId}`)}
                disabled={disableSearch}
              >
                Cauta
              </Button>
            </Box>
          </Grid>
        </div>
      </Grid>
    </Container>
  );
};

export default ScanProducts;
