import {
  FETCH_PRODUCTS_SUCCESS,
  FETCH_PRODUCTS_ERROR,
  RESET,
} from '../actions/actionNames';

const initialState = {
  products: [],
  error: {},
};

const fetchProductsSuccess = (state, products) => ({ ...state, products });
const fetchProductsError = (state, error) => ({ ...state, error });

const productsReducer = (state = initialState, action) => {
  switch (action.type) {
    case FETCH_PRODUCTS_SUCCESS:
      return fetchProductsSuccess(state, action.payload);
    case FETCH_PRODUCTS_ERROR:
      return fetchProductsError(state, action.error);
    case RESET:
      return initialState;
    default:
      return state;
  }
};

export default productsReducer;
