// https://material-ui.com/components/data-grid/rendering/
// https://material-ui.com/components/data-grid/columns/#data-grid-columns

import React, { useState, useEffect } from 'react';
import { useDispatch, useSelector } from 'react-redux';
import {
  Container,
  makeStyles,
  Button,
  TextField,
  Box,
} from '@material-ui/core';
import { DataGrid } from '@material-ui/data-grid';
import { NoteAdd as NoteAddIcon } from '@material-ui/icons';
import { fetchProducts, fetchFilteredProducts } from './actions';
import { computeGridColumns } from './utils';

const useStyles = makeStyles({
  navbarDisplayFlex: {
    height: '80vh',
  },
  searchHeader: {
    display: 'flex',
    alignItems: 'center',
    justifyContent: 'space-between',
  },
  searchLeftBox: {
    display: 'flex',
  },
  searchRightBox: {
    display: 'flex',
  },
  uploadFile: {
    cursor: 'pointer',
    color: '#1D6F42',
  },
});

const Products = (props) => {
  const dispatch = useDispatch();
  const classes = useStyles();

  const { products } = useSelector((state) => state.products);
  const [gridColumns] = useState(computeGridColumns(props));
  const [searchValue, setSearchValue] = useState('');
  const [filterApplied, setFilterApplied] = useState(false);

  useEffect(() => {
    dispatch(fetchProducts());
  }, [dispatch]);

  const onSearchValueChange = (evt) => {
    const { value } = evt.target;
    setSearchValue((prev) => {
      if (prev.length && !value.length && filterApplied) {
        dispatch(fetchProducts());
        setFilterApplied(false);
      }
      return value;
    });
  };

  const onSearchBtnClick = () => {
    if (searchValue.length) {
      setFilterApplied(true);
      dispatch(fetchFilteredProducts(searchValue));
    }
  };

  const onKeyDownPressed = (evt) => {
    evt.stopPropagation();

    if (evt.keyCode === 13) {
      onSearchBtnClick();
    }
  };

  const onUploadFileClick = (evt) => {
    // console.log(evt.target.files);
  };

  return (
    <Container className={classes.navbarDisplayFlex}>
      <Box my={3} className={classes.searchHeader}>
        <Box className={classes.searchLeftBox} onKeyDown={onKeyDownPressed}>
          <TextField
            id="standard-basic"
            label="Cauta..."
            value={searchValue}
            onChange={onSearchValueChange}
          />
          <Box ml={4}>
            <Button
              variant="contained"
              color="primary"
              size="small"
              onClick={onSearchBtnClick}
              disabled={!searchValue.length}
            >
              Cautare
            </Button>
          </Box>
        </Box>
        <Box className={classes.searchRightBox}>
          <Box mr={4}>
            <input
              accept="application/vnd.openxmlformats-officedocument.spreadsheetml.sheet"
              style={{ display: 'none' }}
              id="raised-button-file"
              type="file"
              onChange={onUploadFileClick}
            />
            <label htmlFor="raised-button-file">
              <NoteAddIcon className={classes.uploadFile} fontSize="large" />
            </label>
          </Box>
          <Button
            variant="contained"
            color="primary"
            size="small"
            onClick={() => props.history.push('/add-product')}
          >
            Adauga Produs
          </Button>
        </Box>
      </Box>
      <DataGrid
        columns={gridColumns}
        rows={products.map((product) => ({
          id: product._id,
          ...product,
        }))}
        pageSize={10}
      />
    </Container>
  );
};

export default Products;
