import { GET, POST, PUT } from '../../../utils/http';
import { getBaseApi, paths } from '../../../utils/config';
import * as types from './actionNames';

import { fetchProductsSuccess } from '../../products/actions';

const getSubmitPayload = (data) => {
  const payload = {};
  Object.keys(data).forEach((key) => (payload[key] = data[key].value));
  return payload;
};

export const postNewProduct = (productData, productId, history) => async (
  dispatch
) => {
  try {
    let response;
    if (productId) {
      response = await PUT(
        getBaseApi(),
        `${paths.FETCH_PRODUCTS}/${productId}`,
        getSubmitPayload(productData)
      );
    } else {
      response = await POST(
        getBaseApi(),
        paths.FETCH_PRODUCTS,
        getSubmitPayload(productData)
      );
    }

    dispatch(postNewProductSuccess());
    dispatch(fetchProductsSuccess(response.data.results));
    history.push('/products');
  } catch (error) {
    dispatch(postNewProductError(error.response?.data || error.message));
  }
};

export const postNewProductSuccess = () => ({
  type: types.POST_NEW_PRODUCT_SUCCESS,
});

export const postNewProductError = (error) => ({
  type: types.POST_NEW_PRODUCT_ERROR,
  error,
});

export const resetNewProduct = () => ({
  type: types.RESET,
});

export const fetchProduct = (productId) => async (dispatch, getState) => {
  const state = getState();

  try {
    if (Object.keys(state.products.products).length) {
      const product = state.products.products.find(
        (product) => product._id === productId
      );
      if (product) {
        return dispatch(fetchProductSuccess(product));
      }
    }

    const response = await GET(
      getBaseApi(),
      `${paths.FETCH_PRODUCTS}/${productId}`
    );
    dispatch(fetchProductSuccess(response.data.result));
  } catch (error) {
    dispatch(fetchProductError(error.response?.data || error.message));
  }
};

export const fetchProductSuccess = (product) => ({
  type: types.FETCH_PRODUCT_SUCCESS,
  payload: product,
});

export const fetchProductError = (error) => ({
  type: types.FETCH_PRODUCT_ERROR,
  error,
});
