import {
  // POST_NEW_PROFESSOR_SUCCESS,
  POST_NEW_PROFESSOR_ERROR,
  FETCH_PROFESSOR_SUCCESS,
  FETCH_PROFESSOR_ERROR,
  RESET,
} from '../actions/actionNames';

const initialState = {
  professor: {},
  error: {},
};

const postNewProfessorError = (state, error) => ({ ...state, error });
const fetchProfessorSuccess = (state, professor) => ({ ...state, professor });
const fetchProfessorError = (state, error) => ({ ...state, error });

const addProfessorReducer = (state = initialState, action) => {
  switch (action.type) {
    case POST_NEW_PROFESSOR_ERROR:
      return postNewProfessorError(state, action.error);
    case FETCH_PROFESSOR_SUCCESS:
      return fetchProfessorSuccess(state, action.payload);
    case FETCH_PROFESSOR_ERROR:
      return fetchProfessorError(state, action.error);
    case RESET:
      return initialState;
    default:
      return state;
  }
};

export default addProfessorReducer;
