import React, { useState, useEffect, useCallback } from 'react';
import { useDispatch, useSelector } from 'react-redux';
import {
  Container,
  makeStyles,
  Button,
  TextField,
  Box,
  Grid,
  MenuItem,
} from '@material-ui/core';

import { fetchProfessor, postNewProfessor, resetNewProfessor } from './actions';

import { formInitialData } from './utils';
import * as _ from 'lodash';

const useStyles = makeStyles({
  navbarDisplayFlex: {
    height: '80vh',
  },
  errorMessage: {
    color: '#f44336',
  },
  title: {
    fontSize: '25px',
  },
  form: {
    marginTop: '15px',
  },
});

const AddProfessor = (props) => {
  const dispatch = useDispatch();
  const classes = useStyles();

  const { professorId } = props.match.params;
  const [formData, setFormData] = useState(formInitialData);
  const [editForm, setEditForm] = useState(professorId ? false : true);

  const { professor, error } = useSelector((state) => state.addProfessor);

  useEffect(() => {
    if (professorId) {
      dispatch(fetchProfessor(professorId));
    }

    return () => dispatch(resetNewProfessor());
  }, [dispatch, professorId]);

  const setProfessorToFormData = useCallback(() => {
    if (!Object.keys(professor).length) return;

    setFormData((state) => {
      const newState = _.cloneDeep(state);
      Object.keys(professor).forEach((key) => {
        if (newState[key]) {
          newState[key].value = professor[key];
          newState[key].errors = [];
        }
      });
      return newState;
    });
  }, [professor]);

  useEffect(() => {
    setProfessorToFormData();
  }, [setProfessorToFormData]);

  const onTextFieldChange = (key, value) => {
    const obj = _.cloneDeep(formData[key]);
    obj.value = value;
    if (obj.validation) {
      obj.errors = obj.validation(value);
    }
    setFormData({
      ...formData,
      [key]: obj,
    });
  };

  const onSubmitFormClick = (evt) => {
    evt.preventDefault();

    const _formData = _.cloneDeep(formData);
    Object.keys(_formData).forEach((key) => {
      const obj = _formData[key];
      if (obj.validation) {
        obj.errors = obj.validation(obj.value);
      }
    });

    const valid = !Object.keys(_formData).some(
      (keys) => _formData[keys].errors.length
    );
    if (valid) {
      dispatch(postNewProfessor(_formData, professorId, props.history));
      return;
    }
    setFormData(_formData);
  };

  const onEditFormClick = () => {
    setEditForm(!editForm);
    setProfessorToFormData();
  };

  return (
    <Container className={classes.navbarDisplayFlex}>
      <Grid container justify="space-between" item xs={12}>
        <Box my={3}>
          <p className={classes.title}>
            Adauga Profesor - Mod {editForm ? 'Editare' : 'Read Only'}
          </p>
        </Box>

        <Box my={3}>
          <Grid container>
            {professorId ? (
              <Box mr={3}>
                <Button
                  variant="contained"
                  color="primary"
                  size="medium"
                  type="button"
                  onClick={onEditFormClick}
                >
                  {editForm ? 'Read Only' : 'Editeaza'}
                </Button>
              </Box>
            ) : (
              ''
            )}
            <Box mr={3}>
              <Button
                variant="contained"
                color="primary"
                size="medium"
                type="button"
                onClick={() => props.history.goBack()}
              >
                Inapoi
              </Button>
            </Box>
          </Grid>
        </Box>
      </Grid>

      <form className={classes.form} onSubmit={onSubmitFormClick}>
        <Grid container spacing={3}>
          {Object.keys(formData).map((key) => {
            const obj = formData[key];
            switch (obj.type) {
              case 'input':
                return (
                  <Grid key={key} item xs={3}>
                    <TextField
                      variant={editForm ? 'outlined' : 'standard'}
                      id={key}
                      value={obj.value}
                      label={obj.label}
                      error={!!obj.errors.length}
                      helperText={
                        obj.errors.length ? obj.errors.join('\n') : ' '
                      }
                      onChange={(evt) =>
                        onTextFieldChange(key, evt.target.value)
                      }
                      InputProps={{
                        readOnly: !editForm,
                      }}
                    />
                  </Grid>
                );
              case 'select':
                return (
                  <Grid key={key} item xs={3}>
                    <TextField
                      variant={editForm ? 'outlined' : 'standard'}
                      fullWidth={true}
                      select
                      id={key}
                      value={obj.value}
                      label={obj.label}
                      error={!!obj.errors.length}
                      helperText={
                        obj.errors.length ? obj.errors.join('\n') : ' '
                      }
                      onChange={(evt) =>
                        onTextFieldChange(key, evt.target.value)
                      }
                      InputProps={{
                        readOnly: !editForm,
                      }}
                    >
                      {obj.options.map((option) => (
                        <MenuItem key={option.value} value={option.value}>
                          {option.label}
                        </MenuItem>
                      ))}
                    </TextField>
                  </Grid>
                );
              case 'select-multiple':
                return (
                  <Grid key={key} item xs={3}>
                    <TextField
                      variant={editForm ? 'outlined' : 'standard'}
                      fullWidth={true}
                      select
                      id={key}
                      label={obj.label}
                      error={!!obj.errors.length}
                      helperText={
                        obj.errors.length ? obj.errors.join('\n') : ' '
                      }
                      SelectProps={{
                        multiple: true,
                        value: obj.value,
                        onChange: (evt) =>
                          onTextFieldChange(key, evt.target.value),
                      }}
                      InputProps={{
                        readOnly: !editForm,
                      }}
                    >
                      {obj.options.map((option) => (
                        <MenuItem key={option.value} value={option.value}>
                          {option.label}
                        </MenuItem>
                      ))}
                    </TextField>
                  </Grid>
                );
              case 'date':
                return <Grid key={key} item xs={3}></Grid>;
              default:
                return (
                  <Grid key={key} item xs={3}>
                    <TextField
                      variant={editForm ? 'outlined' : 'standard'}
                      id={key}
                      value={obj.value}
                      label={obj.label}
                      error={!!obj.errors.length}
                      helperText={
                        obj.errors.length ? obj.errors.join(' ') : ' '
                      }
                      onChange={(evt) =>
                        onTextFieldChange(key, evt.target.value)
                      }
                      InputProps={{
                        readOnly: !editForm,
                      }}
                    />
                  </Grid>
                );
            }
          })}
        </Grid>

        <Grid item xs={12} container justify="flex-end">
          <Box mr={5}>
            <Button
              variant="contained"
              color="primary"
              size="medium"
              type="submit"
              disabled={
                Object.keys(formData).some(
                  (key) => formData[key].errors.length
                ) || !editForm
              }
            >
              Trimite
            </Button>
          </Box>
        </Grid>
      </form>
      {Object.keys(error).length ? (
        <p className={classes.errorMessage}>{error.message}</p>
      ) : (
        ''
      )}
    </Container>
  );
};

export default AddProfessor;
