import React, { useState, useEffect } from 'react';

const QrCodeScanner = (props) => {
  const [mounted, setMounted] = useState(false);
  useEffect(() => {
    if (!mounted) {
      const html5QrCode = new window.Html5Qrcode('qr-code-full-region', false);

      // If you want to prefer front camera
      html5QrCode.start(
        { facingMode: 'user' },
        props.config,
        props.onQrCodeSuccess,
        props.onQrCodeError
      );
      setMounted(true);
    }
  }, [mounted, props.config, props.onQrCodeSuccess, props.onQrCodeError]);

  return <div id={'qr-code-full-region'} />;
};

export default QrCodeScanner;
