import React, { useState, useEffect, useCallback } from 'react';
import { useDispatch, useSelector } from 'react-redux';
import {
  Container,
  makeStyles,
  Button,
  TextField,
  Box,
  Grid,
  MenuItem,
} from '@material-ui/core';

import { fetchProduct, postNewProduct, resetNewProduct } from './actions';
import { fetchLocations } from '../locations/actions';
import { fetchProfessors } from '../professors/actions';

import { formInitialData } from './utils';
import * as _ from 'lodash';

const useStyles = makeStyles({
  navbarDisplayFlex: {
    height: '80vh',
  },
  errorMessage: {
    fontSize: '25px',
    color: '#f44336',
  },
  title: {
    fontSize: '25px',
  },
  form: {
    marginTop: '15px',
  },
});

const AddProduct = (props) => {
  const dispatch = useDispatch();
  const classes = useStyles();

  const { productId } = props.match.params;
  const [formData, setFormData] = useState(formInitialData);
  const [editForm, setEditForm] = useState(productId ? false : true);

  const { product, error } = useSelector((state) => state.addProduct);
  const { locations } = useSelector((state) => state.locations);
  const { professors } = useSelector((state) => state.professors);

  useEffect(() => {
    dispatch(fetchLocations());
    dispatch(fetchProfessors());
    if (productId) {
      dispatch(fetchProduct(productId));
    }

    return () => dispatch(resetNewProduct());
  }, [dispatch, productId]);

  useEffect(() => {
    if (!locations.length) return;
    setFormData((state) => ({
      ...state,
      location: {
        ...state.location,
        options: locations.map((location) => ({
          value: location._id,
          label: location.classRoomName,
        })),
      },
    }));
  }, [locations]);

  useEffect(() => {
    if (!professors.length) return;

    setFormData((state) => ({
      ...state,
      productOwner: {
        ...state.productOwner,
        options: professors.map((professor) => ({
          value: professor._id,
          label: `${professor.lastName} ${professor.firstName}`,
        })),
      },
      professors: {
        ...state.professors,
        options: professors.map((professor) => ({
          value: professor._id,
          label: `${professor.lastName} ${professor.firstName}`,
        })),
      },
    }));
  }, [professors]);

  const setProductToFormData = useCallback(() => {
    if (!Object.keys(product).length) return;

    setFormData((state) => {
      const newState = _.cloneDeep(state);
      Object.keys(product).forEach((key) => {
        if (newState[key]) {
          newState[key].value = product[key];
          newState[key].errors = [];
        }
      });
      newState.location.value = newState.location.value._id;
      newState.professors.value = newState.professors.value.map(
        (professor) => professor._id
      );
      newState.productOwner.value = newState.productOwner.value._id;
      return newState;
    });
  }, [product]);

  useEffect(() => {
    setProductToFormData();
  }, [setProductToFormData]);

  const onTextFieldChange = (key, value) => {
    const obj = _.cloneDeep(formData[key]);
    obj.value = value;
    if (obj.validation) {
      obj.errors = obj.validation(value);
    }
    setFormData({
      ...formData,
      [key]: obj,
    });
  };

  const onSubmitFormClick = (evt) => {
    evt.preventDefault();

    const _formData = _.cloneDeep(formData);
    Object.keys(_formData).forEach((key) => {
      const obj = _formData[key];
      if (obj.validation) {
        obj.errors = obj.validation(obj.value);
      }
    });

    const valid = !Object.keys(_formData).some(
      (keys) => _formData[keys].errors.length
    );
    if (valid) {
      dispatch(postNewProduct(_formData, productId, props.history));
      return;
    }
    setFormData(_formData);
  };

  const onEditFormClick = () => {
    setEditForm(!editForm);
    setProductToFormData();
  };

  return (
    <Container className={classes.navbarDisplayFlex}>
      <Grid container justify="space-between" item xs={12}>
        <Box my={3}>
          <p className={classes.title}>
            Adauga Produs - Mod {editForm ? 'Editare' : 'Read Only'}
          </p>
        </Box>

        <Box my={3}>
          <Grid container>
            {productId ? (
              <Box mr={3}>
                <Button
                  variant="contained"
                  color="primary"
                  size="medium"
                  type="button"
                  onClick={onEditFormClick}
                >
                  {editForm ? 'Read Only' : 'Editeaza'}
                </Button>
              </Box>
            ) : (
              ''
            )}
            <Box mr={3}>
              <Button
                variant="contained"
                color="primary"
                size="medium"
                type="button"
                onClick={() => props.history.goBack()}
              >
                Inapoi
              </Button>
            </Box>
          </Grid>
        </Box>
      </Grid>

      <form className={classes.form} onSubmit={onSubmitFormClick}>
        <Grid container spacing={3}>
          {Object.keys(formData).map((key) => {
            const obj = formData[key];
            switch (obj.type) {
              case 'input':
                return (
                  <Grid key={key} item xs={3}>
                    <TextField
                      variant={editForm ? 'outlined' : 'standard'}
                      id={key}
                      value={obj.value}
                      label={obj.label}
                      error={!!obj.errors.length}
                      helperText={
                        obj.errors.length ? obj.errors.join('\n') : ' '
                      }
                      onChange={(evt) =>
                        onTextFieldChange(key, evt.target.value)
                      }
                      InputProps={{
                        readOnly: !editForm,
                      }}
                    />
                  </Grid>
                );
              case 'select':
                return (
                  <Grid key={key} item xs={3}>
                    <TextField
                      variant={editForm ? 'outlined' : 'standard'}
                      fullWidth={true}
                      select
                      id={key}
                      value={obj.value}
                      label={obj.label}
                      error={!!obj.errors.length}
                      helperText={
                        obj.errors.length ? obj.errors.join('\n') : ' '
                      }
                      onChange={(evt) =>
                        onTextFieldChange(key, evt.target.value)
                      }
                      InputProps={{
                        readOnly: !editForm,
                      }}
                    >
                      {obj.options.map((option) => (
                        <MenuItem key={option.value} value={option.value}>
                          {option.label}
                        </MenuItem>
                      ))}
                    </TextField>
                  </Grid>
                );
              case 'select-multiple':
                return (
                  <Grid key={key} item xs={3}>
                    <TextField
                      variant={editForm ? 'outlined' : 'standard'}
                      fullWidth={true}
                      select
                      id={key}
                      label={obj.label}
                      error={!!obj.errors.length}
                      helperText={
                        obj.errors.length ? obj.errors.join('\n') : ' '
                      }
                      SelectProps={{
                        multiple: true,
                        value: obj.value,
                        onChange: (evt) =>
                          onTextFieldChange(key, evt.target.value),
                      }}
                      InputProps={{
                        readOnly: !editForm,
                      }}
                    >
                      {obj.options.map((option) => (
                        <MenuItem key={option.value} value={option.value}>
                          {option.label}
                        </MenuItem>
                      ))}
                    </TextField>
                  </Grid>
                );
              case 'date':
                return <Grid key={key} item xs={3}></Grid>;
              default:
                return (
                  <Grid key={key} item xs={3}>
                    <TextField
                      variant={editForm ? 'outlined' : 'standard'}
                      id={key}
                      value={obj.value}
                      label={obj.label}
                      error={!!obj.errors.length}
                      helperText={
                        obj.errors.length ? obj.errors.join(' ') : ' '
                      }
                      onChange={(evt) =>
                        onTextFieldChange(key, evt.target.value)
                      }
                      InputProps={{
                        readOnly: !editForm,
                      }}
                    />
                  </Grid>
                );
            }
          })}
        </Grid>

        <Grid item xs={12} container justify="flex-end">
          <Box mr={5}>
            <Button
              variant="contained"
              color="primary"
              size="medium"
              type="submit"
              disabled={
                Object.keys(formData).some(
                  (key) => formData[key].errors.length
                ) || !editForm
              }
            >
              Trimite
            </Button>
          </Box>
        </Grid>
      </form>
      {Object.keys(error).length ? (
        <p className={classes.errorMessage}>{error.message}</p>
      ) : (
        ''
      )}
    </Container>
  );
};

export default AddProduct;
