import axios from './interceptors';

export const GET = (url, path, headers = {}) => {
  headers['Authorization'] = '';
  return axios(
    {
      method: 'GET',
      url: `${url}${path}`,
    },
    {
      headers,
    }
  );
};

export const POST = (url, path, data, headers = {}) => {
  headers['Authorization'] = '';
  return axios(
    {
      method: 'POST',
      url: `${url}${path}`,
      data,
    },
    {
      headers,
    }
  );
};

export const PUT = (url, path, data, headers = {}) => {
  headers['Authorization'] = '';
  return axios(
    {
      method: 'PUT',
      url: `${url}${path}`,
      data,
    },
    {
      headers,
    }
  );
};
