import { GET, POST, PUT } from '../../../utils/http';
import { getBaseApi, paths } from '../../../utils/config';
import * as types from './actionNames';

import { fetchProfessorsSuccess } from '../../professors/actions';

const getSubmitPayload = (data) => {
  const payload = {};
  Object.keys(data).forEach((key) => (payload[key] = data[key].value));
  return payload;
};

export const postNewProfessor = (professorData, professorId, history) => async (
  dispatch
) => {
  try {
    let response;
    if (professorId) {
      response = await PUT(
        getBaseApi(),
        `${paths.FETCH_PROFESSORS}/${professorId}`,
        getSubmitPayload(professorData)
      );
    } else {
      response = await POST(
        getBaseApi(),
        paths.FETCH_PROFESSORS,
        getSubmitPayload(professorData)
      );
    }

    dispatch(postNewProfessorSuccess());
    dispatch(fetchProfessorsSuccess(response.data.results));
    history.push('/professors');
  } catch (error) {
    dispatch(postNewProfessorError(error.response?.data || error.message));
  }
};

export const postNewProfessorSuccess = () => ({
  type: types.POST_NEW_PROFESSOR_SUCCESS,
});

export const postNewProfessorError = (error) => ({
  type: types.POST_NEW_PROFESSOR_ERROR,
  error,
});

export const resetNewProfessor = () => ({
  type: types.RESET,
});

export const fetchProfessor = (professorId) => async (dispatch, getState) => {
  const state = getState();

  try {
    if (Object.keys(state.professors.professors).length) {
      const professor = state.professors.professors.find(
        (professor) => professor._id === professorId
      );
      if (professor) {
        return dispatch(fetchProfessorSuccess(professor));
      }
    }

    const response = await GET(
      getBaseApi(),
      `${paths.FETCH_PROFESSORS}/${professorId}`
    );
    dispatch(fetchProfessorSuccess(response.data.result));
  } catch (error) {
    dispatch(fetchProfessorError(error.response?.data || error.message));
  }
};

export const fetchProfessorSuccess = (professor) => ({
  type: types.FETCH_PROFESSOR_SUCCESS,
  payload: professor,
});

export const fetchProfessorError = (error) => ({
  type: types.FETCH_PROFESSOR_ERROR,
  error,
});
