import { GET } from '../../../utils/http';
import { getBaseApi, paths } from '../../../utils/config';
import * as types from './actionNames';

export const fetchLocations = () => async (dispatch) => {
  try {
    const response = await GET(getBaseApi(), paths.FETCH_LOCATIONS);
    dispatch(fetchLocationsSuccess(response.data.results));
  } catch (error) {
    dispatch(fetchLocationsError(error.response?.data || error.message));
  }
};

export const fetchLocationsSuccess = (locations) => ({
  type: types.FETCH_LOCATIONS_SUCCESS,
  payload: locations,
});

export const fetchLocationsError = (error) => ({
  type: types.FETCH_LOCATIONS_ERROR,
  error,
});
