import { GET } from '../../../utils/http';
import { getBaseApi, paths } from '../../../utils/config';
import * as types from './actionNames';

export const fetchProfessors = () => async (dispatch) => {
  try {
    const response = await GET(getBaseApi(), paths.FETCH_PROFESSORS);
    dispatch(fetchProfessorsSuccess(response.data.results));
  } catch (error) {
    dispatch(fetchProfessorsError(error.response?.data || error.message));
  }
};

export const fetchProfessorsSuccess = (professors) => ({
  type: types.FETCH_PROFESSORS_SUCCESS,
  payload: professors,
});

export const fetchProfessorsError = (error) => ({
  type: types.FETCH_PROFESSORS_ERROR,
  error,
});
