import { GET } from '../../../utils/http';
import { getBaseApi, paths } from '../../../utils/config';
import * as types from './actionNames';

export const fetchProducts = () => async (dispatch) => {
  try {
    const response = await GET(getBaseApi(), paths.FETCH_PRODUCTS);
    dispatch(fetchProductsSuccess(response.data.results));
  } catch (error) {
    dispatch(fetchProductsError(error.response?.data || error.message));
  }
};

export const fetchProductsSuccess = (products) => ({
  type: types.FETCH_PRODUCTS_SUCCESS,
  payload: products,
});

export const fetchProductsError = (error) => ({
  type: types.FETCH_PRODUCTS_ERROR,
  error,
});

export const fetchFilteredProducts = (search) => async (dispatch) => {
  try {
    const response = await GET(
      getBaseApi(),
      paths.FETCH_PRODUCTS + `?search=${search}`
    );
    dispatch(fetchProductsSuccess(response.data.results));
  } catch (error) {
    dispatch(fetchProductsError(error.response?.data || error.message));
  }
};
