import {
  FETCH_COUNTER,
  INCREMENT,
  DECREMENT,
  RESET,
} from '../actions/actionNames';

const initialState = {
  counter: 0,
  loading: false,
};

const fetchCounterData = (state, counter) => ({ ...state, counter });

const incrementCounter = (state) => ({
  ...state,
  counter: state.counter + 1,
});

const decrementCounter = (state) => ({
  ...state,
  counter: state.counter - 1,
});

const scanProductReducer = (state = initialState, action) => {
  switch (action.type) {
    case FETCH_COUNTER:
      return fetchCounterData(state, action.payload);
    case INCREMENT:
      return incrementCounter(state);
    case DECREMENT:
      return decrementCounter(state);
    case RESET:
      return initialState;
    default:
      return state;
  }
};

export default scanProductReducer;
