import {
  FETCH_PROFESSORS_SUCCESS,
  FETCH_PROFESSORS_ERROR,
  RESET,
} from '../actions/actionNames';

const initialState = {
  professors: [],
  error: {},
};

const fetchProfessorsSuccess = (state, professors) => ({
  ...state,
  professors,
});
const fetchProfessorsError = (state, error) => ({ ...state, error });

const professorsReducer = (state = initialState, action) => {
  switch (action.type) {
    case FETCH_PROFESSORS_SUCCESS:
      return fetchProfessorsSuccess(state, action.payload);
    case FETCH_PROFESSORS_ERROR:
      return fetchProfessorsError(state, action.error);
    case RESET:
      return initialState;
    default:
      return state;
  }
};

export default professorsReducer;
