import React from 'react';
import {
  AppBar,
  Toolbar,
  IconButton,
  List,
  ListItem,
  ListItemText,
  Container,
  makeStyles,
} from '@material-ui/core';
import { Home } from '@material-ui/icons';
import { Link, NavLink } from 'react-router-dom';

const navLinks = [
  { title: 'Scanare Produs', path: '/scan' },
  { title: 'Produse', path: '/products' },
  { title: 'Locatii', path: '/locations' },
  { title: 'Profesori', path: '/professors' },
  { title: 'Istoric citiri', path: '/scanningHistory' },
];

const useStyles = makeStyles({
  navbarDisplayFlex: {
    display: 'flex',
    justifyContent: 'space-between',
  },
  navDisplayFlex: {
    display: 'flex',
    justifyContent: 'space-between',
  },
  linkText: {
    textDecoration: 'none',
    color: 'white',
  },
  linkTextLogout: {
    marginLeft: '3rem',
    textDecoration: 'none',
    color: '#FF851B',
  },
  activeClassName: {
    color: '#FF851B',
  },
});

const Navigation = () => {
  const classes = useStyles();

  return (
    <AppBar position="static">
      <Toolbar>
        <Container className={classes.navbarDisplayFlex}>
          <Link to="/" className={classes.linkText}>
            <IconButton edge="start" color="inherit" aria-label="home">
              <Home fontSize="large" />
            </IconButton>
          </Link>
          <List
            component="nav"
            aria-labelledby="main navigation"
            className={classes.navDisplayFlex}
          >
            {navLinks.map(({ title, path }) => (
              <NavLink
                to={path}
                key={title}
                className={classes.linkText}
                activeClassName={classes.activeClassName}
              >
                <ListItem button>
                  <ListItemText primary={title} />
                </ListItem>
              </NavLink>
            ))}
            <div className={classes.linkTextLogout}>
              <ListItem button>
                <ListItemText primary={'Logout'} />
              </ListItem>
            </div>
          </List>
        </Container>
      </Toolbar>
    </AppBar>
  );
};

export default Navigation;
