import {
  Check as CheckIcon,
  Delete as DeleteIcon,
  Block as BlockIcon,
} from '@material-ui/icons';
import { Button, Chip } from '@material-ui/core';

export const gridColumnLabels = {
  _id: ' ',
  inventoryNumber: 'Nr. Inventar',
  productName: 'Denumire Produs',
  managementEntryDate: 'Data intrare gestiune',
  productStatus: 'Status Produs',
  location: 'Locatie',
  professors: 'Profesori',
};

export const computeGridColumns = (props) =>
  Object.keys(gridColumnLabels).map((key) => {
    const defaultWidth = 180;
    const defaultObject = {
      field: key,
      headerName: gridColumnLabels[key],
      width: defaultWidth,
    };

    switch (key) {
      case 'productStatus':
        return {
          ...defaultObject,
          renderCell: (params) => {
            let color;
            let icon;
            switch (params.value) {
              case 'Activ':
                color = 'primary';
                icon = <CheckIcon />;
                break;
              case 'Casabil':
                color = 'default';
                icon = <DeleteIcon />;
                break;
              case 'Casat':
                color = 'secondary';
                icon = <BlockIcon />;
                break;
              default:
                color = 'default';
                icon = <DeleteIcon />;
            }

            return (
              <Chip
                variant="outlined"
                color={color}
                size="small"
                icon={icon}
                label={params.value}
              />
            );
          },
        };
      case '_id':
        return {
          ...defaultObject,
          width: 120,
          renderCell: (params) => {
            return (
              <Button
                variant="contained"
                color="primary"
                size="small"
                style={{ marginLeft: 16 }}
                onClick={() => props.history.push(`/products/${params.value}`)}
              >
                Detalii
              </Button>
            );
          },
        };

      default:
        return defaultObject;
    }
  });
