// https://material-ui.com/components/data-grid/rendering/
// https://material-ui.com/components/data-grid/columns/#data-grid-columns

import React, { useState, useEffect } from 'react';
import { useDispatch, useSelector } from 'react-redux';
import { Container, makeStyles, Button, Box } from '@material-ui/core';
import { DataGrid } from '@material-ui/data-grid';
import { fetchLocations } from './actions';
import { computeGridColumns } from './utils';

const useStyles = makeStyles({
  navbarDisplayFlex: {
    height: '80vh',
  },
  searchHeader: {
    display: 'flex',
    alignItems: 'center',
    justifyContent: 'space-between',
  },
  searchRightBox: {
    display: 'flex',
  },
  title: {
    fontSize: '25px',
  },
});

const Locations = (props) => {
  const dispatch = useDispatch();
  const classes = useStyles();

  const { locations } = useSelector((state) => state.locations);
  const [gridColumns] = useState(computeGridColumns(props));

  useEffect(() => {
    dispatch(fetchLocations());
  }, [dispatch]);

  return (
    <Container className={classes.navbarDisplayFlex}>
      <Box my={3} className={classes.searchHeader}>
        <Box>
          <p className={classes.title}>Locatii</p>
        </Box>
        <Box className={classes.searchRightBox}>
          <Button
            variant="contained"
            color="primary"
            size="medium"
            onClick={() => props.history.push('/add-location')}
          >
            Adauga Locatie
          </Button>
        </Box>
      </Box>
      <DataGrid
        columns={gridColumns}
        rows={locations.map((location) => ({
          id: location._id,
          ...location,
        }))}
        pageSize={10}
      />
    </Container>
  );
};

export default Locations;
