import React from 'react';
import { BrowserRouter, Route, Switch } from 'react-router-dom';
import {
  ScanProducts,
  Products,
  AddProduct,
  Locations,
  AddLocation,
  Professors,
  AddProfessor,
} from '../modules';
import { LoadingScreen, Navigation } from '../components';

const AppRoute = () => (
  <BrowserRouter>
    <Navigation />
    <Switch>
      <Route exact path="/" component={ScanProducts} />
      <Route exact path="/scan" component={ScanProducts} />

      <Route exact path="/products" component={Products} />
      <Route exact path="/products/:productId" component={AddProduct} />
      <Route exact path="/add-product" component={AddProduct} />

      <Route exact path="/locations" component={Locations} />
      <Route exact path="/locations/:locationId" component={AddLocation} />
      <Route exact path="/add-location" component={AddLocation} />

      <Route exact path="/professors" component={Professors} />
      <Route exact path="/professors/:professorId" component={AddProfessor} />
      <Route exact path="/add-professor" component={AddProfessor} />
    </Switch>
    <LoadingScreen />
  </BrowserRouter>
);

export default AppRoute;
