import { GET, POST, PUT } from '../../../utils/http';
import { getBaseApi, paths } from '../../../utils/config';
import * as types from './actionNames';

import { fetchLocationsSuccess } from '../../locations/actions';

const getSubmitPayload = (data) => {
  const payload = {};
  Object.keys(data).forEach((key) => (payload[key] = data[key].value));
  return payload;
};

export const postNewLocation = (locationData, locationdId, history) => async (
  dispatch
) => {
  try {
    let response;
    if (locationdId) {
      response = await PUT(
        getBaseApi(),
        `${paths.FETCH_LOCATIONS}/${locationdId}`,
        getSubmitPayload(locationData)
      );
    } else {
      response = await POST(
        getBaseApi(),
        paths.FETCH_LOCATIONS,
        getSubmitPayload(locationData)
      );
    }

    dispatch(postNewLocationSuccess());
    dispatch(fetchLocationsSuccess(response.data.results));
    history.push('/locations');
  } catch (error) {
    dispatch(postNewLocationError(error.response?.data || error.message));
  }
};

export const postNewLocationSuccess = () => ({
  type: types.POST_NEW_LOCATION_SUCCESS,
});

export const postNewLocationError = (error) => ({
  type: types.POST_NEW_LOCATION_ERROR,
  error,
});

export const resetNewLocation = () => ({
  type: types.RESET,
});

export const fetchLocation = (locationdId) => async (dispatch, getState) => {
  const state = getState();

  try {
    if (Object.keys(state.locations.locations).length) {
      const location = state.locations.locations.find(
        (location) => location._id === locationdId
      );
      if (location) {
        return dispatch(fetchLocationSuccess(location));
      }
    }

    const response = await GET(
      getBaseApi(),
      `${paths.FETCH_LOCATIONS}/${locationdId}`
    );
    dispatch(fetchLocationSuccess(response.data.result));
  } catch (error) {
    dispatch(fetchLocationError(error.response?.data || error.message));
  }
};

export const fetchLocationSuccess = (location) => ({
  type: types.FETCH_LOCATION_SUCCESS,
  payload: location,
});

export const fetchLocationError = (error) => ({
  type: types.FETCH_LOCATION_ERROR,
  error,
});
