import { combineReducers } from 'redux';

import globalReducer from './globalReducer';
import scanProductsReducer from '../modules/scanProducts/reducer';

import productsReducer from '../modules/products/reducer';
import addProductReducer from '../modules/addProduct/reducer';

import locationsReducer from '../modules/locations/reducer';
import addLocationReducer from '../modules/addLocation/reducer';

import professorsReducer from '../modules/professors/reducer';
import addProfessorReducer from '../modules/addProfessor/reducer';

const rootReducer = combineReducers({
  globalReducer,
  scanProduct: scanProductsReducer,
  products: productsReducer,
  locations: locationsReducer,
  professors: professorsReducer,
  addProduct: addProductReducer,
  addLocation: addLocationReducer,
  addProfessor: addProfessorReducer,
});
export default rootReducer;
